// ── Notion: HTTP cru + paginação (this.helpers vem do runtime do Code node) ──
const NOTION_TOKEN = $env.NOTION_TOKEN;
const NOTION_VERSION = $env.NOTION_VERSION || '2022-06-28';
const HELPERS = this.helpers;
function notionHeaders() {
  return { Authorization: `Bearer ${NOTION_TOKEN}`, 'Notion-Version': NOTION_VERSION, 'Content-Type': 'application/json' };
}
async function notionQueryAll(databaseId, filter, sorts) {
  let results = [];
  let cursor;
  do {
    const body = { page_size: 100 };
    if (filter) body.filter = filter;
    if (sorts) body.sorts = sorts;
    if (cursor) body.start_cursor = cursor;
    const resp = await HELPERS.httpRequest({
      method: 'POST',
      url: `https://api.notion.com/v1/databases/${databaseId}/query`,
      headers: notionHeaders(),
      body,
      json: true,
    });
    results = results.concat(resp.results || []);
    cursor = resp.has_more ? resp.next_cursor : null;
  } while (cursor);
  return results;
}
async function notionCreatePage(databaseId, properties) {
  return HELPERS.httpRequest({
    method: 'POST',
    url: 'https://api.notion.com/v1/pages',
    headers: notionHeaders(),
    body: { parent: { database_id: databaseId }, properties },
    json: true,
  });
}
async function notionUpdatePage(pageId, properties) {
  return HELPERS.httpRequest({
    method: 'PATCH',
    url: `https://api.notion.com/v1/pages/${pageId}`,
    headers: notionHeaders(),
    body: { properties },
    json: true,
  });
}

// ── Glue: Lançamentos + Contas Fixas + Metas ativas ──
const [lancamentos, contasFixas, metasAtivas] = await Promise.all([
  notionQueryAll($env.NOTION_DB_LANCAMENTOS),
  notionQueryAll($env.NOTION_DB_CONTAS_FIXAS),
  notionQueryAll($env.NOTION_DB_METAS, { property: 'Status', select: { equals: 'ativa' } }),
]);
return [{ json: { lancamentos, contasFixas, metasAtivas } }];

// Rateio proporcional ao salário — lógica pura do dashboard da reunião familiar.
// TDD em rateio.test.js. Módulo Node consumido pelo runner (não é Code node n8n).
// Implementa gstack/specs/dashboard-reuniao-familiar.md.

/** Remove acento e caixa para comparar categorias/nomes (Deposito ~ Depósito). */
function normalizar(s) {
  return String(s == null ? "" : s)
    .normalize("NFD").replace(/[̀-ͯ]/g, "").trim().toLowerCase();
}

const arred = (n) => Math.round(n * 100) / 100;

/**
 * Valor da planilha → número. Defesa contra `valor` gravado como TEXTO (ex.: o nó
 * googleSheets em USER_ENTERED + locale pt_BR pode coagir "1011.87" a texto). Aceita
 * número nativo, "1011.87" (ponto decimal), BR "1.011,56"/"1011,56" e "R$ 1.234,56".
 * Lixo/vazio → 0 (nunca NaN — NaN envenenaria a soma inteira do relatório).
 */
function valorNum(v) {
  if (typeof v === "number") return Number.isFinite(v) ? v : 0;
  if (v === null || v === undefined) return 0;
  let s = String(v).trim().replace(/^R\$\s*/i, "");
  if (s === "") return 0;
  if (s.includes(",")) s = s.replace(/\./g, "").replace(",", ".");        // BR: ponto=milhar, vírgula=decimal
  else if ((s.match(/\./g) || []).length > 1) s = s.replace(/\./g, "");   // só pontos múltiplos = milhar
  const n = Number(s);
  return Number.isFinite(n) ? n : 0;
}

/**
 * Categorias de transferência interna — movimentação entre contas próprias
 * (ex.: pagar a fatura do cartão, resgate/aplicação, Pix para si mesmo). NÃO são
 * consumo nem receita: o gasto real já está nas compras da fatura (origem=cartao)
 * e contá-las de novo no extrato duplicaria. O parser resolve "Pagamento/Retirada"
 * para uma destas conforme a direção (entrada→Pagamento, saída→Retirada).
 */
const CATEGORIAS_TRANSFERENCIA = new Set(["pagamento", "retirada"]);
function ehTransferencia(categoria) {
  return CATEGORIAS_TRANSFERENCIA.has(normalizar(categoria));
}

/** salarios: {pessoa: salario} ou [{pessoa, salario}] → {pessoa: proporção}. */
function proporcoes(salarios) {
  const pares = Array.isArray(salarios)
    ? salarios.map((s) => [s.pessoa, Number(s.salario)])
    : Object.entries(salarios).map(([p, v]) => [p, Number(v)]);
  const total = pares.reduce((s, [, v]) => s + v, 0);
  if (!(total > 0)) throw new Error("soma dos salários deve ser > 0 (configurar aba Salários)");
  const out = {};
  for (const [p, v] of pares) out[p] = v / total;
  return out;
}

/**
 * Data da planilha → "MM/YYYY" | null. Aceita os três formatos que o nó de
 * leitura pode devolver (valueRenderOption=UNFORMATTED_VALUE):
 *   - "DD/MM/YYYY" (string) ;
 *   - "YYYY-MM-DD" (string ISO) ;
 *   - serial do Sheets (número ou string só-dígitos): célula formatada como
 *     Data volta como dias desde 1899-12-30, não como string.
 */
function mesDe(v) {
  if (v === null || v === undefined || v === "") return null;
  if (typeof v === "number" || (typeof v === "string" && /^\d+(\.\d+)?$/.test(v.trim()))) {
    const serial = Math.floor(Number(v));
    if (!Number.isFinite(serial) || serial <= 0) return null;
    const d = new Date(Date.UTC(1899, 11, 30) + serial * 86400000);
    return `${String(d.getUTCMonth() + 1).padStart(2, "0")}/${d.getUTCFullYear()}`;
  }
  const s = String(v).trim();
  let m;
  if ((m = /^\d{2}\/(\d{2})\/(\d{4})$/.exec(s))) return `${m[1]}/${m[2]}`;
  if ((m = /^(\d{4})-(\d{2})-\d{2}/.exec(s))) return `${m[2]}/${m[1]}`;
  return null;
}

/** "MM/YYYY" → número YYYYMM comparável (ex.: "05/2026" → 202605); inválido → null. */
function mesParaNum(mes) {
  const m = /^(\d{2})\/(\d{4})$/.exec(String(mes == null ? "" : mes).trim());
  if (!m) return null;
  return Number(m[2]) * 100 + Number(m[1]);
}

/**
 * Pessoa dona de uma categoria exclusiva "Gastos {pessoa}", ou null. Despesa
 * exclusiva NÃO é dividida por salário: é cobrada 100% de quem é (decisão do Marcelo).
 */
function categoriaExclusivaDe(categoria, pessoas) {
  const c = normalizar(categoria);
  for (const p of pessoas) {
    if (c === "gastos " + normalizar(p)) return p;
  }
  return null;
}

/**
 * Movimentação PESSOAL (não é da casa): "Depósito para o/a {pessoa}" (entrada) e
 * "Saída para o/a {pessoa}" (saída). Dinheiro que passou pela conta mas é pessoal —
 * ex.: Pix de terceiros que era do Marcelo + o Pix que ele mandou de volta p/ si.
 * APARECE no fluxo de caixa (entradas/saídas), mas é NEUTRA ao rateio: não é
 * contribuição (pago) nem custo/dívida da casa (base/cota). Distingue-se de "Retirada"
 * (pgto de fatura / aplicação CDB), que é transferência excluída de tudo.
 */
function ehMovimentacaoPessoal(categoria) {
  const c = normalizar(categoria);
  return /^deposito para /.test(c) || /^saida para /.test(c);
}

/**
 * Categoria de META ("Meta: Viagem Lua de Mel", "Meta: IPTU", ...). É poupança/objetivo
 * rastreado à parte na aba Metas — NÃO é despesa mensal compartilhada da casa. Fica FORA
 * do rateio e do treemap de gastos da casa (decisão do Marcelo). Aparece no fluxo de caixa.
 */
function ehMeta(categoria) {
  return /^meta:/.test(normalizar(categoria));
}

/**
 * Núcleo do rateio sobre um conjunto JÁ filtrado de lançamentos (DRY entre rateioMes
 * e rateioAcumulado). `prop` = proporções por pessoa (de proporcoes()).
 * - base dividida = saídas confirmadas não-transferência, não-exclusivas e não-pessoais;
 * - exclusivo[p] = Σ saídas confirmadas "Gastos {p}" (100% da pessoa);
 * - cota[p] = base × prop[p] + exclusivo[p];   pago[p] = entradas "Depósito {p}";
 * - saldo = pago − cota;  acerto = cota − pago (positivo = a pessoa deve).
 * Movimentações pessoais ("Depósito/Saída para o ...") são IGNORADAS aqui (neutras).
 * Conservação: Σ cotas = base + Σ exclusivos = Σ saídas confirmadas não-transferência/pessoais.
 * @returns {{totalDespesas, cota, pago, saldo, acerto}}
 */
function calcularRateio(lancamentos, prop) {
  const pessoas = Object.keys(prop);
  const exclusivo = {};
  for (const p of pessoas) exclusivo[p] = 0;
  let base = 0;
  for (const l of lancamentos) {
    if (l.tipo !== "saída" || l.status !== "confirmado") continue;
    // fora do rateio: transferência interna, movimentação pessoal e Metas (poupança à parte)
    if (ehTransferencia(l.categoria) || ehMovimentacaoPessoal(l.categoria) || ehMeta(l.categoria)) continue;
    const dono = categoriaExclusivaDe(l.categoria, pessoas);
    if (dono) exclusivo[dono] = arred(exclusivo[dono] + valorNum(l.valor));
    else base = arred(base + valorNum(l.valor));
  }
  const totalDespesas = arred(base + pessoas.reduce((s, p) => s + exclusivo[p], 0));

  // Divide a base entre as pessoas; a ÚLTIMA absorve o resíduo de arredondamento para
  // garantir Σ(parte dividida) == base exatamente — sem dívida-fantasma de R$ 0,01 no
  // saldo cumulativo (que nunca quitaria). O exclusivo de cada um soma à parte dele.
  const parteBase = {};
  let alocado = 0;
  pessoas.forEach((p, idx) => {
    if (idx === pessoas.length - 1) parteBase[p] = arred(base - alocado);
    else { parteBase[p] = arred(base * prop[p]); alocado = arred(alocado + parteBase[p]); }
  });

  const cota = {}, pago = {}, saldo = {}, acerto = {};
  for (const p of pessoas) {
    cota[p] = arred(parteBase[p] + exclusivo[p]);
    const alvo = normalizar(`deposito ${p}`);
    pago[p] = arred(lancamentos
      .filter((l) => l.tipo === "entrada" && normalizar(l.categoria) === alvo)
      .reduce((s, l) => s + valorNum(l.valor), 0));
    saldo[p] = arred(pago[p] - cota[p]);
    acerto[p] = arred(cota[p] - pago[p]);
  }
  return { totalDespesas, cota, pago, saldo, acerto };
}

/**
 * Rateio do mês (`mes` = "MM/YYYY"). Visão de um único mês (usada no relatório).
 * @returns {{mes, totalDespesas, proporcoes, cota, pago, saldo, acerto}}
 */
function rateioMes(lancamentos, salarios, mes) {
  const prop = proporcoes(salarios);
  const doMes = lancamentos.filter((l) => mesDe(l.data_competencia) === mes);
  return { mes, proporcoes: prop, ...calcularRateio(doMes, prop) };
}

/**
 * Rateio CUMULATIVO: meses com `mesInicio ≤ mesDe ≤ mesAte`. Detecta dívida acumulada
 * (decisão do Marcelo). `mesInicio` (opcional, "MM/YYYY") é o marco onde a conta da casa
 * começa — meses anteriores (pré-rastreio) ficam de fora. Lançamentos com data ilegível
 * (`mesDe===null`) são descartados.
 * @returns {{mesAte, mesInicio, acumulado:true, totalDespesas, proporcoes, cota, pago, saldo, acerto}}
 */
function rateioAcumulado(lancamentos, salarios, mesAte, mesInicio) {
  const prop = proporcoes(salarios);
  const ate = mesParaNum(mesAte);
  const inicio = mesParaNum(mesInicio);
  const ateOuAntes = lancamentos.filter((l) => {
    const m = mesParaNum(mesDe(l.data_competencia));
    return m !== null && (ate === null || m <= ate) && (inicio === null || m >= inicio);
  });

  const mesesSet = new Set();
  for (const l of ateOuAntes) {
    const m = mesDe(l.data_competencia);
    if (m) mesesSet.add(m);
  }
  const mesesOrdenados = [...mesesSet].sort((a, b) => mesParaNum(a) - mesParaNum(b));

  const pessoas = Object.keys(prop);
  // FONTE ÚNICA: os totais do card são a SOMA mês-a-mês (mesmo cálculo do histórico do
  // modal). Antes o card vinha de um calcularRateio agregado separado, que podia divergir
  // da soma do modal em centavos (resíduo de arredondamento absorvido 1× vs N×). Agora o
  // card == última linha de saldoAcumulado do histórico, sempre.
  const cota = {}, pago = {}, saldo = {}, acerto = {};
  for (const p of pessoas) { cota[p] = 0; pago[p] = 0; saldo[p] = 0; acerto[p] = 0; }
  let totalDespesas = 0;
  const historico = [];

  for (const m of mesesOrdenados) {
    const doMes = lancamentos.filter((l) => mesDe(l.data_competencia) === m);
    const rMes = calcularRateio(doMes, prop);

    totalDespesas = arred(totalDespesas + rMes.totalDespesas);
    for (const p of pessoas) {
      cota[p] = arred(cota[p] + rMes.cota[p]);
      pago[p] = arred(pago[p] + rMes.pago[p]);
      saldo[p] = arred(saldo[p] + rMes.saldo[p]);
      acerto[p] = arred(cota[p] - pago[p]);
    }

    const exclusivoMes = {};
    for (const p of pessoas) {
      exclusivoMes[p] = 0;
      for (const l of doMes) {
        if (l.tipo === "saída" && l.status === "confirmado"
          && categoriaExclusivaDe(l.categoria, pessoas) === p) {
          exclusivoMes[p] = arred(exclusivoMes[p] + valorNum(l.valor));
        }
      }
    }

    historico.push({
      mes: m,
      totalDespesas: rMes.totalDespesas,
      cota: rMes.cota,
      exclusivo: exclusivoMes,
      pago: rMes.pago,
      saldo: rMes.saldo,
      saldoAcumulado: { ...saldo }, // == card (soma corrente) — modal e card sempre batem
    });
  }

  return { mesAte, mesInicio: mesInicio || null, acumulado: true, proporcoes: prop, totalDespesas, cota, pago, saldo, acerto, historico };
}


// Agregações do dashboard da reunião familiar — lógica pura. TDD em dashboard.test.js.
// Módulo Node consumido pelo runner (não é Code node n8n).
// Implementa gstack/specs/dashboard-reuniao-familiar.md.
/**
 * Gastos da casa do mês por categoria: `previsto` (Conta Fixa ativa, valor esperado),
 * `confirmado` (saída confirmada do mês) e `orcamento` (teto de acompanhamento). Inclui
 * categorias com gasto confirmado E contas fixas ativas ainda não pagas (previsto>0,
 * confirmado=0) — assim dá p/ ver o que falta pagar.
 * Exclui transferência, movimentação pessoal e Metas (só gastos da casa).
 *
 * `orcamento` = teto da aba Orçamentos (linha ativa) se houver; senão cai no `previsto`
 * (valor_esperado da Conta Fixa). É a base da barra de progresso da UI (não escreve em
 * Contas Fixas — previsão/lembretes ficam intactos). 0 = sem teto → UI não desenha barra.
 * Categoria só com teto (sem confirmado nem previsto) NÃO entra: o conjunto é conf ∪ prev.
 * @param {{categoria, teto_mensal, ativo}[]} [orcamentos=[]] aba Orçamentos (A:C)
 * @returns {{categoria, previsto, confirmado, orcamento}[]} ordenado por confirmado desc, depois previsto.
 */
function gastosPorCategoria(lancamentos, mes, contasFixas, orcamentos) {
  const conf = new Map();
  for (const l of lancamentos) {
    if (l.tipo !== "saída" || l.status !== "confirmado" || mesDe(l.data_competencia) !== mes) continue;
    if (ehTransferencia(l.categoria) || ehMovimentacaoPessoal(l.categoria) || ehMeta(l.categoria)) continue;
    conf.set(l.categoria, (conf.get(l.categoria) || 0) + valorNum(l.valor));
  }
  const prev = new Map();
  for (const f of contasFixas || []) {
    if (normalizar(f.ativo) === "sim") {
      prev.set(f.nome, arred((prev.get(f.nome) || 0) + valorNum(f.valor_esperado)));
    }
  }
  // Teto de acompanhamento (aba Orçamentos). Mesma chave de categoria que conf/prev usam —
  // sem normalização nova. Só registra teto > 0; inválido/vazio/0 cai no fallback (previsto).
  const teto = new Map();
  for (const o of orcamentos || []) {
    if (normalizar(o.ativo) !== "sim") continue;
    const t = valorNum(o.teto_mensal);
    if (t > 0) teto.set(o.categoria, arred(t));
  }
  const cats = new Set([...conf.keys(), ...prev.keys()]);
  return [...cats]
    .map((categoria) => {
      const previsto = arred(prev.get(categoria) || 0);
      return {
        categoria,
        previsto,
        confirmado: arred(conf.get(categoria) || 0),
        orcamento: teto.has(categoria) ? teto.get(categoria) : previsto,
      };
    })
    .sort((a, b) => (b.confirmado - a.confirmado) || (b.previsto - a.previsto));
}

/**
 * Totais confirmados do mês: saídas, entradas, saldo. É a visão de FLUXO DE CAIXA — inclui
 * movimentações pessoais ("Depósito/Saída para o ..."), que o usuário quer ver entrando/saindo.
 * Só exclui transferências internas (pgto de fatura / aplicação CDB), que dobrariam contagem.
 * (Logo, `saidas` pode ser > Σ gastosPorCategoria, que mostra só os gastos da casa.)
 */
function totaisMes(lancamentos, mes) {
  const soma = (tipo) => arred(lancamentos
    .filter((l) => l.tipo === tipo && l.status === "confirmado" && mesDe(l.data_competencia) === mes
      && !ehTransferencia(l.categoria))
    .reduce((s, l) => s + valorNum(l.valor), 0));
  const saidas = soma("saída");
  const entradas = soma("entrada");
  return { saidas, entradas, saldo: arred(entradas - saidas) };
}

/**
 * Previsão do próximo mês (`mes` = "MM/YYYY"): parcelas já lançadas (saídas
 * previstas do mês) + projeção das contas fixas ativas cuja categoria ainda NÃO
 * aparece no mês. Depósitos previstos = total × proporção (regra do Marcelo).
 * @param {{nome, valor_esperado, ativo}[]} contasFixas aba Contas Fixas
 * @returns {{gastos:{fixas,parcelas,total}, depositosPrevistos:{[pessoa]:number}}}
 */
function previsaoProximoMes(lancamentos, contasFixas, salarios, mes, faturaAbertaRows) {
  const prop = proporcoes(salarios);
  const pessoas = Object.keys(prop);

  // 1. Gastos fixos ativos
  const fixas = arred((contasFixas || [])
    .filter((f) => normalizar(f.ativo) === "sim")
    .reduce((s, f) => s + valorNum(f.valor_esperado), 0));

  // 2. Fatura aberta fechada que VENCE no mês previsto (ciclo vence dia 10/MM). A previsão
  //    de 03/2026 soma a fatura cujo vencimento cai em 03/2026 — não qualquer fatura capturada.
  const faFechadas = (faturaAbertaRows || []).filter((r) =>
    normalizar(r.status) === "fechado" && mesDe(normalizarCiclo(r.ciclo)) === mes);
  const faturaTotal = arred(faFechadas.reduce((s, r) => s + valorNum(r.valor), 0));

  // 3. Gastos exclusivos/pessoais na fatura aberta
  const exclusivoFatura = {};
  for (const p of pessoas) {
    exclusivoFatura[p] = 0;
  }
  for (const r of faFechadas) {
    const dono = categoriaExclusivaDe(r.categoria_c6, pessoas);
    if (dono) {
      exclusivoFatura[dono] = arred(exclusivoFatura[dono] + valorNum(r.valor));
    }
  }
  const exclusivoFaturaTotal = arred(pessoas.reduce((s, p) => s + exclusivoFatura[p], 0));

  // 4. Base comum (compartilhada)
  const faturaBase = arred(faturaTotal - exclusivoFaturaTotal);
  const totalPrevistoBase = arred(fixas + faturaBase);

  // 5. Rateio da base proporcional ao salário (conservação de resíduo de arredondamento)
  const parteBase = {};
  let alocado = 0;
  pessoas.forEach((p, idx) => {
    if (idx === pessoas.length - 1) {
      parteBase[p] = arred(totalPrevistoBase - alocado);
    } else {
      parteBase[p] = arred(totalPrevistoBase * prop[p]);
      alocado = arred(alocado + parteBase[p]);
    }
  });

  // 6. Depósito previsto = cota base proporcional + gastos exclusivos individuais
  const depositosPrevistos = {};
  for (const p of pessoas) {
    depositosPrevistos[p] = arred(parteBase[p] + exclusivoFatura[p]);
  }

  // 7. Detalhes
  const detalhes = [];
  for (const f of contasFixas || []) {
    if (normalizar(f.ativo) === "sim") {
      detalhes.push({ categoria: f.nome, valor: valorNum(f.valor_esperado) });
    }
  }
  if (faturaTotal > 0) {
    detalhes.push({ categoria: "Fatura Cartão C6", valor: faturaTotal });
  }

  const total = arred(fixas + faturaTotal);

  return { gastos: { fixas, parcelas: faturaTotal, total }, detalhes, depositosPrevistos };
}

/**
 * Comprometido futuro (v2): fatura aberta do ciclo corrente + projeção das parcelas.
 * Prospectivo a partir de `hojeISO` (YYYY-MM-DD) — independe do seletor de mês. Bloco
 * separado da previsão (anti-dupla-contagem): a projeção é derivada da aba `Parcelas`,
 * nunca de `Lançamentos`.
 * @param {object[]} faturaAbertaRows linhas da aba FaturaAberta (A:G)
 * @param {object[]} parcelasRows linhas da aba Parcelas (A:E) — ciclo_referencia em serial
 * @param {object[]} configRows aba Config (chave|valor) — comprometido_horizonte (default 6)
 * @returns {{faturaAberta:{ciclo,total,status,porCategoria}|null, parcelas:{vencimento,total}[], horizonte:number}}
 */
function comprometidoFuturo(faturaAbertaRows, parcelasRows, configRows, hojeISO) {
  let horizonte = 6;
  const cfg = (configRows || []).find((r) => normalizar(r.chave) === "comprometido_horizonte");
  if (cfg && Math.floor(Number(cfg.valor)) > 0) horizonte = Math.floor(Number(cfg.valor));

  // Fatura aberta: só status='fechado' (R3 — rascunho/não-fechado fora do dashboard).
  let faFechadas = (faturaAbertaRows || []).filter((r) => normalizar(r.status) === "fechado");
  let faturaAberta = null;
  if (faFechadas.length) {
    // A aba é clear+write de um único ciclo; mas se sobrarem 'fechado' de ciclos diferentes
    // (reseed parcial), ancora no ciclo mais recente — evita total e rótulo divergirem.
    const ciclos = [...new Set(faFechadas.map((r) => normalizarCiclo(r.ciclo)))]
      .filter(Boolean)
      .sort((a, b) => -(mesesEntreVencimentos(a, b) || 0)); // crescente (mesesEntre = b−a)
    const ciclo = ciclos[ciclos.length - 1];
    faFechadas = faFechadas.filter((r) => normalizarCiclo(r.ciclo) === ciclo);
    const total = arred(faFechadas.reduce((s, r) => s + valorNum(r.valor), 0));
    const catMap = new Map();
    for (const r of faFechadas) {
      const c = (r.categoria_c6 && String(r.categoria_c6).trim()) || "Outros";
      catMap.set(c, (catMap.get(c) || 0) + valorNum(r.valor));
    }
    const porCategoria = [...catMap.entries()]
      .map(([categoria, t]) => ({ categoria, total: arred(t) }))
      .sort((a, b) => b.total - a.total);
    faturaAberta = { ciclo, total, status: "fechado", porCategoria };
  }

  // Âncora = max(ciclo da fatura aberta, vencimento do ciclo aberto de hoje) — Q2.
  // Se vencHoje falhar (hoje malformado), usa o ciclo da fatura aberta como âncora.
  const vencHoje = vencimentoCicloAberto(hojeISO);
  let ancora = vencHoje;
  if (faturaAberta && (!vencHoje || mesesEntreVencimentos(vencHoje, faturaAberta.ciclo) > 0)) {
    ancora = faturaAberta.ciclo;
  }

  const parcelaRows = (parcelasRows || []).map((r) => ({
    estabelecimento: r.estabelecimento,
    valor: valorNum(r.valor),
    M: Number(r.M),
    N_no_seed: Number(r.N_no_seed),
    ciclo_referencia: normalizarCiclo(r.ciclo_referencia),
  }));
  const parcelas = ancora ? projetarComprometido(parcelaRows, ancora, horizonte) : [];
  return { faturaAberta, parcelas, horizonte };
}


// Lógica pura da gestão de metas — progresso derivado dos Lançamentos, mensagem
// e teclados inline do /metas, parse de /novameta e dos callbacks gm*.
// Implementa gstack/plans/gerenciar-metas.md.
//
// Progresso é SEMPRE derivado dos Lançamentos (fonte da verdade); a coluna C de
// Metas (valor_acumulado) é só cache reescrito no glue, nunca lida como fonte.
// CRUD distinto da associação lançamento→meta da categorização (prefixo meta|).

const TEMPLATE_NOVAMETA =
  "Para criar uma meta, envie:\n" +
  "/novameta <nome> | <orçamento> | <prazo>\n" +
  "Ex.: /novameta Cama Nova | 1800 | 2026-12";

function formatarReal(n) {
  const [int, dec] = Number(n).toFixed(2).split(".");
  return `R$ ${int.replace(/\B(?=(\d{3})+(?!\d))/g, ".")},${dec}`;
}

function assertCb(botao) {
  if (Buffer.byteLength(botao.callback_data, "utf-8") > 64) {
    throw new Error(`callback_data excede 64 bytes: ${botao.callback_data}`);
  }
  return botao;
}

/**
 * Progresso de cada meta ATIVA, derivado dos Lançamentos.
 * acumulado = Σ |valor| dos lançamentos com status=confirmado e id_meta==nome
 * (match exato após trim dos dois lados — espaço de borda casa, case-sensitive).
 * @param {Array<{nome,orcamento_total,prazo,status}>} metas aba Metas (A:F)
 * @param {Array<{valor,status,id_meta}>} lancamentos aba Lançamentos (A:J)
 * @returns {Array<{nome,orcamento,acumulado,pct:(number|null),prazo}>}
 */
function calcularProgresso(metas, lancamentos) {
  return (metas || [])
    .filter((m) => String(m.status || "").trim().toLowerCase() === "ativa")
    .map((m) => {
      const nome = String(m.nome || "").trim();
      const orcamento = Number(m.orcamento_total) || 0;
      const acumulado = (lancamentos || [])
        .filter(
          (l) =>
            String(l.status || "").trim().toLowerCase() === "confirmado" &&
            String(l.id_meta || "").trim() === nome
        )
        .reduce((s, l) => s + Math.abs(Number(l.valor) || 0), 0);
      const pct = orcamento > 0 ? Math.round((acumulado / orcamento) * 100) : null;
      return { nome, orcamento, acumulado, pct, prazo: String(m.prazo || "").trim() };
    });
}

/** Mensagem do /metas: lista cada meta ativa; vazio → convite a criar. */
function montarMensagemMetas(progresso) {
  if (!progresso || progresso.length === 0) {
    return `🎯 Você ainda não tem metas ativas.\n\n${TEMPLATE_NOVAMETA}`;
  }
  const linhas = progresso.map((p) => {
    const acum = formatarReal(p.acumulado);
    if (p.pct === null) return `🎯 ${p.nome}\n   ${acum} acumulado · até ${p.prazo}`;
    return `🎯 ${p.nome}\n   ${acum} / ${formatarReal(p.orcamento)} (${p.pct}%) · até ${p.prazo}`;
  });
  return `Suas metas ativas:\n\n${linhas.join("\n\n")}`;
}

/** Teclado do /metas: 🏁 Encerrar por meta (gmenc|) + linha final ➕ Nova meta (gmnova|). */
function montarTecladoMetas(progresso) {
  const linhas = (progresso || []).map((p) => [
    assertCb({ text: `🏁 Encerrar ${p.nome}`, callback_data: `gmenc|${p.nome}` }),
  ]);
  linhas.push([assertCb({ text: "➕ Nova meta", callback_data: "gmnova|" })]);
  return { inline_keyboard: linhas };
}

/** Teclado de confirmação de encerramento (2 toques): ✅ Confirmar → gmok|<nome>. */
function montarTecladoConfirmarEncerrar(nome) {
  return {
    inline_keyboard: [
      [assertCb({ text: "✅ Confirmar encerramento", callback_data: `gmok|${nome}` })],
    ],
  };
}

/** Valor em formato BR: ponto milhar, vírgula decimal. Inválido → null. */
function parsearValorBR(bruto) {
  const s = String(bruto || "")
    .replace(/r\$/i, "")
    .replace(/\s/g, "")
    .replace(/\./g, "")
    .replace(",", ".");
  if (s === "") return null;
  const n = Number(s);
  return Number.isFinite(n) ? n : null;
}

/** Prazo aceito: AAAA-MM ou AAAA-MM-DD (mês 1–12, dia 1–31). */
function prazoValido(prazo) {
  const m = /^(\d{4})-(\d{2})(?:-(\d{2}))?$/.exec(String(prazo || "").trim());
  if (!m) return false;
  const mes = Number(m[2]);
  if (mes < 1 || mes > 12) return false;
  if (m[3]) {
    const dia = Number(m[3]);
    if (dia < 1 || dia > 31) return false;
  }
  return true;
}

/** Nome de meta: trim, não vazio, sem '|', curto o bastante p/ caber no callback_data. */
function validarNomeMeta(nome) {
  const n = String(nome || "").trim();
  if (n === "") return { ok: false, erro: "Nome da meta não pode ser vazio." };
  if (n.includes("|")) return { ok: false, erro: "Nome da meta não pode conter '|'." };
  if (Buffer.byteLength(`gmok|${n}`, "utf-8") > 64) {
    return { ok: false, erro: "Nome da meta longo demais (máx ~59 caracteres)." };
  }
  return { ok: true, nome: n };
}

/**
 * Interpreta `/novameta <nome> | <orçamento> | <prazo>` (stateless).
 * @returns {{ok:true, meta:{nome,orcamento,prazo}} | {ok:false, erro:string}}
 */
function parsearNovaMeta(texto) {
  const corpo = String(texto || "").replace(/^\/novameta(@\S+)?/i, "").trim();
  const partes = corpo.split("|").map((p) => p.trim());
  const erroFmt = (msg) => ({ ok: false, erro: `${msg}\n\n${TEMPLATE_NOVAMETA}` });
  if (partes.length !== 3 || partes.some((p) => p === "")) {
    return erroFmt("Formato inválido — preencha nome, orçamento e prazo separados por '|'.");
  }
  const [nomeBruto, orcamentoBruto, prazo] = partes;
  const vn = validarNomeMeta(nomeBruto);
  if (!vn.ok) return erroFmt(vn.erro);
  const orcamento = parsearValorBR(orcamentoBruto);
  if (orcamento === null || orcamento <= 0) return erroFmt("Orçamento inválido — use um número, ex.: 1800.");
  if (!prazoValido(prazo)) return erroFmt("Prazo inválido — use AAAA-MM, ex.: 2026-12.");
  return { ok: true, meta: { nome: vn.nome, orcamento, prazo } };
}

/** Já existe meta ATIVA com esse nome? (homônimo de encerrada é permitido). */
function nomeJaExisteAtiva(nome, metas) {
  const alvo = String(nome || "").trim();
  return (metas || []).some(
    (m) =>
      String(m.status || "").trim().toLowerCase() === "ativa" &&
      String(m.nome || "").trim() === alvo
  );
}

/** Parse dos callbacks gm*. gmnova| → nova; gmenc|<nome>; gmok|<nome>. Inválido → null. */
function parsearCallbackMetaGestao(data) {
  const s = String(data || "");
  if (s === "gmnova|") return { acao: "nova" };
  const m = /^(gmenc|gmok)\|(.+)$/.exec(s);
  if (!m) return null;
  return { acao: m[1] === "gmenc" ? "encerrar-confirmar" : "encerrar-ok", nome: m[2] };
}


// Resumo mensal do dashboard em texto plano (sem HTML — vira o corpo de UM bloco de
// parágrafo do Notion, que preserva quebras de linha embutidas). Reaproveita
// totaisMes/gastosPorCategoria (dashboard.js), arred (rateio.js) e calcularProgresso
// (metas.js) sem alteração. Requires normais (mesmo padrão de relatorio-notion-extra.js)
// — o gerador remove essas linhas antes de concatenar tudo num só Code node.



function brl(n) {
  const [int, dec] = Math.abs(arred(Number(n))).toFixed(2).split(".");
  return `R$ ${int.replace(/\B(?=(\d{3})+(?!\d))/g, ".")},${dec}`;
}

/**
 * @param {{lancamentos, contasFixas, metas}} dados metas = SÓ as ativas (aba/database já filtrada)
 * @param {string} mes "MM/YYYY"
 * @returns {{saidas, entradas, saldo, metasAtivas, texto}} texto = corpo do bloco Notion
 */
function montarResumoDashboardNotion(dados, mes) {
  const { lancamentos, contasFixas, metas } = dados;
  const tot = totaisMes(lancamentos, mes);
  const cats = gastosPorCategoria(lancamentos, mes, contasFixas, []);
  const prog = calcularProgresso(metas, lancamentos);

  const L = [];
  L.push(`Saídas: ${brl(tot.saidas)}`);
  L.push(`Entradas: ${brl(tot.entradas)}`);
  L.push(`Saldo: ${brl(tot.saldo)}${tot.saldo < 0 ? " (negativo)" : ""}`);

  if (cats.length) {
    L.push("");
    L.push("Por categoria:");
    for (const c of cats.slice(0, 10)) {
      const pct = c.orcamento > 0 ? ` de ${brl(c.orcamento)} (${Math.round((c.confirmado / c.orcamento) * 100)}%)` : "";
      L.push(`• ${c.categoria}: ${brl(c.confirmado)}${pct}`);
    }
  }

  if (prog.length) {
    L.push("");
    L.push("Metas ativas:");
    for (const p of prog) {
      const alvo = p.orcamento > 0 ? ` / ${brl(p.orcamento)}` : "";
      const pct = p.pct === null ? "" : ` (${p.pct}%)`;
      L.push(`🎯 ${p.nome}: ${brl(p.acumulado)}${alvo}${pct} · até ${p.prazo}`);
    }
  }

  return { saidas: tot.saidas, entradas: tot.entradas, saldo: tot.saldo, metasAtivas: prog.length, texto: L.join("\n") };
}

// Mapeamento puro entre o shape "flat" usado pela lógica de negócio reaproveitada de
// workflows/src/*.js (parser-cartao, parser-conta, dashboard, rateio, ...) e o formato
// de properties da API do Notion (POST /v1/pages, POST /v1/databases/{id}/query).
// Sem I/O — só transformação de dados. Concatenado nos Code nodes do n8n junto com
// os módulos puros originais (ver scripts/gerar-workflow-*-notion.js).
// Implementa a Fase A de gstack (schema em workflows-harumi/README... ver plano da branch).

/** "DD/MM/YYYY" ou "YYYY-MM-DD" → "YYYY-MM-DD" (Notion exige ISO); inválido/vazio → null. */
function paraIso(data) {
  if (data === null || data === undefined || data === "") return null;
  const s = String(data).trim();
  let m;
  if ((m = /^(\d{4})-(\d{2})-(\d{2})/.exec(s))) return `${m[1]}-${m[2]}-${m[3]}`;
  if ((m = /^(\d{2})\/(\d{2})\/(\d{4})$/.exec(s))) return `${m[3]}-${m[2]}-${m[1]}`;
  return null;
}

/**
 * Texto plano de uma property title/rich_text do Notion. As demais funções de
 * leitura (paraObjeto*) devolvem "YYYY-MM-DD" para datas — mesDe()/normalizarData()
 * em workflows/src/*.js já aceitam esse formato ISO nativamente, então nenhuma
 * conversão adicional é necessária na leitura (só na escrita, via paraIso).
 */
function textoDe(prop) {
  if (!prop) return "";
  const arr = prop.title || prop.rich_text || [];
  return arr.map((t) => t.plain_text || "").join("");
}

const richText = (s) => (s ? [{ text: { content: String(s).slice(0, 2000) } }] : []);
const selectOrNull = (s) => (s ? { select: { name: String(s) } } : { select: null });
const dateOrNull = (isoOuBr) => {
  const iso = paraIso(isoOuBr);
  return iso ? { date: { start: iso } } : { date: null };
};

// ─── Lançamentos ────────────────────────────────────────────────────────────

/** Page do Notion (results[i] de um query em Lançamentos) → objeto flat esperado pelos parsers/dashboard. */
function paraObjetoLancamento(page) {
  const p = (page && page.properties) || {};
  return {
    _id: page && page.id,
    data_competencia: (p["Data Competência"] && p["Data Competência"].date && p["Data Competência"].date.start) || "",
    data_original: (p["Data Original"] && p["Data Original"].date && p["Data Original"].date.start) || "",
    descricao: textoDe(p["Descrição"]),
    titulo: "",
    valor: (p["Valor"] && p["Valor"].number) || 0,
    categoria: (p["Categoria"] && p["Categoria"].select && p["Categoria"].select.name) || "",
    tipo: (p["Tipo"] && p["Tipo"].select && p["Tipo"].select.name) || "",
    origem: (p["Origem"] && p["Origem"].select && p["Origem"].select.name) || "",
    status: (p["Status"] && p["Status"].select && p["Status"].select.name) || "",
    id_meta: textoDe(p["Meta"]),
  };
}

/** Objeto flat (saída do parser-cartao/parser-conta) → properties para criar a page no Notion. */
function propsDeLancamento(l) {
  return {
    "Descrição": { title: richText(l.descricao || l.titulo || "(sem descrição)") },
    "Valor": { number: Number(l.valor) || 0 },
    "Categoria": selectOrNull(l.categoria),
    "Tipo": selectOrNull(l.tipo),
    "Origem": selectOrNull(l.origem),
    "Status": selectOrNull(l.status),
    "Meta": { rich_text: richText(l.id_meta) },
    "Data Competência": dateOrNull(l.data_competencia),
    "Data Original": dateOrNull(l.data_original),
  };
}

/** Update parcial (PATCH) de um Lançamento: só Categoria+Meta — não toca nas demais properties. */
function propsCategoriaEMeta(categoria, idMeta) {
  return { "Categoria": selectOrNull(categoria), "Meta": { rich_text: richText(idMeta) } };
}

// ─── Dicionário ─────────────────────────────────────────────────────────────

function paraObjetoDicionario(page) {
  const p = (page && page.properties) || {};
  return {
    _id: page && page.id,
    descricao_original: textoDe(p["Descrição Original"]),
    categoria_mapeada: (p["Categoria Mapeada"] && p["Categoria Mapeada"].select && p["Categoria Mapeada"].select.name) || "",
    origem: (p["Origem"] && p["Origem"].select && p["Origem"].select.name) || "",
    criado_em: (p["Criado Em"] && p["Criado Em"].date && p["Criado Em"].date.start) || "",
  };
}

/** Dicionário lido vira { chave, categoria } (contrato de parser-cartao.categorizar / parser-conta). */
function paraDicionarioChaveCategoria(objetosDicionario) {
  return objetosDicionario.map((d) => ({ chave: d.descricao_original, categoria: d.categoria_mapeada }));
}

function propsDeDicionario(d) {
  // Criado Em nunca fica vazio: cai no dia de hoje se d.criado_em não vier preenchido.
  const criadoEm = paraIso(d.criado_em) || new Date().toISOString().slice(0, 10);
  return {
    "Descrição Original": { title: richText(d.descricao_original || "(vazio)") },
    "Categoria Mapeada": selectOrNull(d.categoria_mapeada),
    "Origem": selectOrNull(d.origem),
    "Criado Em": { date: { start: criadoEm } },
